module RefModule (q, clk, reset);
   input clk, reset;
   output [3:0] q;

   reg [3:0] q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
    if (reset)
    begin
        q <= 4'b0000;
    end
    else
    begin
        q <= {q[2:0], ~q[3]};
    end
end //End of always block

endmodule
